    private DateTime weekStart;
    private List<Appointment> appointments = new();
    private List<Pet> pets = new();
    private bool showForm;
    private Appointment? selectedAppointment;

    protected override async Task OnInitializedAsync()
    {
        GoToToday();
        pets = await Db.Pets.OrderBy(p => p.Name).ToListAsync();
        await LoadAppointments();
    }

    private void GoToToday()
    {
        var today = DateTime.Today;
        weekStart = today.AddDays(-(int)today.DayOfWeek);
    }

    private async Task PreviousWeek()
    {
        weekStart = weekStart.AddDays(-7);
        await LoadAppointments();
    }

    private async Task NextWeek()
    {
        weekStart = weekStart.AddDays(7);
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        var weekEnd = weekStart.AddDays(7);
        appointments = await Db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.ScheduledAt >= weekStart && a.ScheduledAt < weekEnd && a.Status != AppointmentStatus.Cancelled)
            .ToListAsync();
    }

    private Appointment? GetAppointmentAt(DateTime slotTime)
    {
        return appointments.FirstOrDefault(a => a.ScheduledAt.Date == slotTime.Date && a.ScheduledAt.Hour == slotTime.Hour);
    }

    private void OpenCreateForm(DateTime slotTime)
    {
        selectedAppointment = new Appointment { ScheduledAt = slotTime };
        showForm = true;
    }

    private void SelectAppointment(Appointment appt)
    {
        selectedAppointment = appt;
        showForm = true;
    }

    private void CloseForm()
    {
        showForm = false;
        selectedAppointment = null;
    }

    private async Task SaveAppointment()
    {
        if (selectedAppointment == null || selectedAppointment.PetId == 0) return;
        if (selectedAppointment.Id == 0)
            Db.Appointments.Add(selectedAppointment);
        await Db.SaveChangesAsync();
        await LoadAppointments();
        showForm = false;
        selectedAppointment = null;
    }

    private async Task CancelAppointment()
    {
        if (selectedAppointment == null) return;
        selectedAppointment.Status = AppointmentStatus.Cancelled;
        await Db.SaveChangesAsync();
        await LoadAppointments();
        showForm = false;
        selectedAppointment = null;
    }
}
