                    <td>@p.PaymentDate.ToShortDateString()</td>
                    <td>@p.Amount.ToString("C")</td>
                    <td>@p.Method</td>
                    <td>@p.Reference</td>
                </tr>
            }
        </tbody>
    </table>

    @if (invoice.Status != InvoiceStatus.Paid)
    {
        <div class="card mt-3">
            <div class="card-body">
                <h5>Process Payment</h5>
                <div class="row g-2">
                    <div class="col-md-3">
                        <label class="form-label">Amount</label>
                        <input type="number" step="0.01" class="form-control" @bind="paymentAmount" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Method</label>
                        <select class="form-select" @bind="paymentMethod">
                            @foreach (var m in Enum.GetValues<PaymentMethod>())
                            {
                                <option value="@m">@m</option>
                            }
                        </select>
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Reference</label>
                        <input class="form-control" @bind="paymentReference" />
                    </div>
                    <div class="col-md-3 d-flex align-items-end">
                        <button class="btn btn-success" @onclick="ProcessPayment">Record Payment</button>
                    </div>
                </div>
            </div>
        </div>
    }
}

@code {
    [Parameter] public int Id { get; set; }

    private Invoice? invoice;
    private decimal paymentAmount;
    private PaymentMethod paymentMethod = PaymentMethod.Cash;
    private string paymentReference = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoice();
    }

    private async Task LoadInvoice()
    {
        invoice = await Db.Invoices
            .Include(i => i.Pet)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == Id);
        if (invoice != null)
            paymentAmount = invoice.TotalAmount - invoice.AmountPaid;
    }

    private async Task ProcessPayment()
    {
        if (invoice == null || paymentAmount <= 0) return;
        var payment = new Payment
        {
            InvoiceId = invoice.Id,
            Amount = paymentAmount,
            Method = paymentMethod,
            Reference = paymentReference,
            PaymentDate = DateTime.UtcNow
        };
        Db.Payments.Add(payment);
        invoice.AmountPaid += paymentAmount;
        invoice.Status = invoice.AmountPaid >= invoice.TotalAmount ? InvoiceStatus.Paid : InvoiceStatus.PartiallyPaid;
        await Db.SaveChangesAsync();
        await LoadInvoice();
        paymentReference = string.Empty;
    }

    private string GetStatusBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Pending => "bg-warning text-dark",
        InvoiceStatus.PartiallyPaid => "bg-info",
        InvoiceStatus.Overdue => "bg-danger",
        _ => "bg-secondary"
    };
}
```

