@page "/"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@attribute [Authorize]
@inject ApplicationDbContext Db

<PageTitle>Dashboard - VetClinic Manager</PageTitle>

<h1>Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4 mb-3">
        <div class="card text-bg-primary">
            <div class="card-body">
                <h5 class="card-title">Total Patients</h5>
                <p class="card-text display-4">@totalPatients</p>
            </div>
        </div>
    </div>
    <div class="col-md-4 mb-3">
        <div class="card text-bg-success">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-4">@todaysAppointments</p>
            </div>
        </div>
    </div>
    <div class="col-md-4 mb-3">
        <div class="card text-bg-warning">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <p class="card-text display-4">@pendingInvoices</p>
            </div>
        </div>
    </div>
</div>

@code {
    private int totalPatients;
    private int todaysAppointments;
    private int pendingInvoices;

    protected override async Task OnInitializedAsync()
    {
        totalPatients = await Db.Pets.CountAsync();
        var today = DateTime.Today;
        todaysAppointments = await Db.Appointments
            .Where(a => a.ScheduledAt.Date == today && a.Status == AppointmentStatus.Scheduled)
            .CountAsync();
        pendingInvoices = await Db.Invoices
            .Where(i => i.Status == InvoiceStatus.Pending || i.Status == InvoiceStatus.Overdue)
            .CountAsync();
    }
}

@page "/patients"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@attribute [Authorize]
@inject ApplicationDbContext Db
@inject NavigationManager Nav

<PageTitle>Patients - VetClinic Manager</PageTitle>

<h1>Patients</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by name, species, or owner..." @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-primary" @onclick="ShowAddForm">+ Add Patient</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <h5>@(editingPet?.Id > 0 ? "Edit" : "New") Patient</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <input class="form-control" placeholder="Name *" @bind="editingPet!.Name" />
                </div>
                <div class="col-md-2">
                    <input class="form-control" placeholder="Species *" @bind="editingPet!.Species" />
                </div>
                <div class="col-md-2">
                    <input class="form-control" placeholder="Breed" @bind="editingPet!.Breed" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Owner Name *" @bind="editingPet!.OwnerName" />
                </div>
                <div class="col-md-2">
                    <input class="form-control" placeholder="Owner Phone" @bind="editingPet!.OwnerPhone" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Owner Email" @bind="editingPet!.OwnerEmail" />
                </div>
                <div class="col-md-3">
                    <input type="date" class="form-control" @bind="editingPet!.DateOfBirth" />
                </div>
                <div class="col-md-4">
                    <input class="form-control" placeholder="Notes" @bind="editingPet!.Notes" />
                </div>
                <div class="col-md-2">
                    <button class="btn btn-success me-1" @onclick="SavePet">Save</button>
                    <button class="btn btn-secondary" @onclick="CancelEdit">Cancel</button>
                </div>
            </div>
        </div>
    </div>
}

<table class="table table-striped">
    <thead>
        <tr>
            <th>Name</th>
            <th>Species</th>
            <th>Breed</th>
            <th>Owner</th>
            <th>Phone</th>
            <th>Actions</th>
        </tr>
    </thead>
    <tbody>
        @foreach (var pet in FilteredPets)
        {
            <tr>
                <td>@pet.Name</td>
                <td>@pet.Species</td>
                <td>@pet.Breed</td>
                <td>@pet.OwnerName</td>
                <td>@pet.OwnerPhone</td>
                <td>
                    <button class="btn btn-sm btn-outline-primary me-1" @onclick="() => Nav.NavigateTo($&quot;/patients/{pet.Id}&quot;)">View</button>
                    <button class="btn btn-sm btn-outline-secondary" @onclick="() => EditPet(pet)">Edit</button>
                </td>
            </tr>
        }
    </tbody>
</table>

@code {
    private List<Pet> pets = new();
    private string searchTerm = string.Empty;
    private bool showForm;
    private Pet? editingPet;

    private IEnumerable<Pet> FilteredPets => string.IsNullOrWhiteSpace(searchTerm)
        ? pets
        : pets.Where(p =>
            p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
            p.Species.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
            p.OwnerName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync()
    {
        pets = await Db.Pets.OrderBy(p => p.Name).ToListAsync();
    }

    private void ShowAddForm()
    {
        editingPet = new Pet();
        showForm = true;
    }

    private void EditPet(Pet pet)
    {
        editingPet = pet;
        showForm = true;
    }

    private void CancelEdit()
    {
        showForm = false;
        editingPet = null;
    }

    private async Task SavePet()
    {
        if (editingPet == null) return;
        if (string.IsNullOrWhiteSpace(editingPet.Name) || string.IsNullOrWhiteSpace(editingPet.Species) || string.IsNullOrWhiteSpace(editingPet.OwnerName)) return;

        if (editingPet.Id == 0)
        {
            editingPet.CreatedAt = DateTime.UtcNow;
            Db.Pets.Add(editingPet);
        }
        await Db.SaveChangesAsync();
        pets = await Db.Pets.OrderBy(p => p.Name).ToListAsync();
        showForm = false;
        editingPet = null;
    }
}

