<PageTitle>Patient Details - VetClinic Manager</PageTitle>

@if (pet == null)
{
    <p>Loading...</p>
}
else
{
    <h1>@pet.Name</h1>
    <p><a href="/patients">&larr; Back to Patients</a></p>

    <div class="card mb-4">
        <div class="card-body">
            <h5>Patient Information</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <label class="form-label">Name</label>
                    <input class="form-control" @bind="pet.Name" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Species</label>
                    <input class="form-control" @bind="pet.Species" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Breed</label>
                    <input class="form-control" @bind="pet.Breed" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Date of Birth</label>
                    <input type="date" class="form-control" @bind="pet.DateOfBirth" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Owner Name</label>
                    <input class="form-control" @bind="pet.OwnerName" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Owner Phone</label>
                    <input class="form-control" @bind="pet.OwnerPhone" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Owner Email</label>
                    <input class="form-control" @bind="pet.OwnerEmail" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Notes</label>
                    <input class="form-control" @bind="pet.Notes" />
                </div>
            </div>
            <button class="btn btn-primary mt-2" @onclick="SavePet">Save Changes</button>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h5>Medical History</h5>
            <button class="btn btn-sm btn-success mb-2" @onclick="ShowAddRecord">+ Add Medical Record</button>

            @if (showRecordForm)
            {
                <div class="border rounded p-3 mb-3">
                    <div class="row g-2">
                        <div class="col-md-3">
                            <input type="date" class="form-control" @bind="newRecord!.Date" />
                        </div>
                        <div class="col-md-3">
                            <input class="form-control" placeholder="Diagnosis *" @bind="newRecord!.Diagnosis" />
                        </div>
                        <div class="col-md-3">
                            <input class="form-control" placeholder="Treatment" @bind="newRecord!.Treatment" />
                        </div>
                        <div class="col-md-3">
                            <input class="form-control" placeholder="Medications" @bind="newRecord!.Medications" />
                        </div>
                        <div class="col-md-4">
                            <input class="form-control" placeholder="Veterinarian" @bind="newRecord!.VeterinarianName" />
                        </div>
                        <div class="col-md-4">
                            <input class="form-control" placeholder="Notes" @bind="newRecord!.Notes" />
                        </div>
                        <div class="col-md-4">
                            <button class="btn btn-success me-1" @onclick="SaveRecord">Save</button>
                            <button class="btn btn-secondary" @onclick="() => showRecordForm = false">Cancel</button>
                        </div>
                    </div>
                </div>
            }

            <table class="table table-sm">
                <thead>
                    <tr><th>Date</th><th>Diagnosis</th><th>Treatment</th><th>Medications</th><th>Vet</th><th>Notes</th></tr>
                </thead>
                <tbody>
                    @foreach (var r in records)
                    {
                        <tr>
                            <td>@r.Date.ToShortDateString()</td>
                            <td>@r.Diagnosis</td>
                            <td>@r.Treatment</td>
                            <td>@r.Medications</td>
                            <td>@r.VeterinarianName</td>
                            <td>@r.Notes</td>
