                    <input class="form-control" @bind="selectedAppointment!.Notes" />
                </div>
                <div class="col-md-6 d-flex align-items-end gap-1">
                    <button class="btn btn-success" @onclick="SaveAppointment">Save</button>
                    @if (selectedAppointment?.Id > 0)
                    {
                        <button class="btn btn-danger" @onclick="CancelAppointment">Cancel Appointment</button>
                    }
                    <button class="btn btn-secondary" @onclick="CloseForm">Close</button>
                </div>
