@page "/appointments"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@attribute [Authorize]
@inject ApplicationDbContext Db

<PageTitle>Appointments - VetClinic Manager</PageTitle>

<h1>Appointments</h1>

<div class="d-flex justify-content-between mb-3">
    <div>
        <button class="btn btn-outline-secondary me-1" @onclick="PreviousWeek">&larr; Previous</button>
        <button class="btn btn-outline-secondary me-1" @onclick="NextWeek">Next &rarr;</button>
        <button class="btn btn-outline-primary" @onclick="GoToToday">Today</button>
    </div>
    <span class="fs-5">@weekStart.ToString("MMM d") - @weekStart.AddDays(6).ToString("MMM d, yyyy")</span>
</div>

<div class="table-responsive">
    <table class="table table-bordered" style="table-layout: fixed;">
        <thead>
            <tr>
                <th style="width: 80px;">Time</th>
                @for (int d = 0; d < 7; d++)
                {
                    var date = weekStart.AddDays(d);
                    <th class="text-center @(date == DateTime.Today ? "table-info" : "")">@date.ToString("ddd M/d")</th>
                }
            </tr>
        </thead>
        <tbody>
            @for (int hour = 8; hour <= 17; hour++)
            {
                <tr>
                    <td class="text-nowrap small">@(new TimeOnly(hour, 0).ToString("h:mm tt"))</td>
                    @for (int d = 0; d < 7; d++)
                    {
                        var slotDate = weekStart.AddDays(d);
                        var slotTime = new DateTime(slotDate.Year, slotDate.Month, slotDate.Day, hour, 0, 0);
                        var appt = GetAppointmentAt(slotTime);
                        if (appt != null)
                        {
                            <td class="table-primary small p-1" @onclick="() => SelectAppointment(appt)" style="cursor:pointer;">
                                <strong>@appt.Pet?.Name</strong><br/>
                                <span>@appt.Reason</span>
                            </td>
                        }
                        else
                        {
                            <td class="table-success p-1" @onclick="() => OpenCreateForm(slotTime)" style="cursor:pointer; opacity: 0.5;">
                                &nbsp;
                            </td>
                        }
                    }
                </tr>
            }
        </tbody>
    </table>
</div>

@if (showForm)
{
    <div class="card mt-3">
        <div class="card-body">
            <h5>@(selectedAppointment?.Id > 0 ? "Edit Appointment" : "New Appointment")</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <label class="form-label">Pet</label>
                    <select class="form-select" @bind="selectedAppointment!.PetId">
                        <option value="0">-- Select Pet --</option>
                        @foreach (var p in pets)
                        {
                            <option value="@p.Id">@p.Name (@p.Species)</option>
                        }
                    </select>
                </div>
                <div class="col-md-3">
                    <label class="form-label">Date/Time</label>
                    <input type="datetime-local" class="form-control" @bind="selectedAppointment!.ScheduledAt" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Duration (min)</label>
                    <input type="number" class="form-control" @bind="selectedAppointment!.DurationMinutes" />
                </div>
