            <div class="row g-2 mb-2">
                <div class="col-md-4">
                    <label class="form-label">Pet</label>
                    <select class="form-select" @bind="newInvoice!.PetId">
                        <option value="0">-- Select Pet --</option>
                        @foreach (var p in pets)
                        {
                            <option value="@p.Id">@p.Name (@p.OwnerName)</option>
                        }
                    </select>
                </div>
                <div class="col-md-3">
                    <label class="form-label">Invoice Date</label>
                    <input type="date" class="form-control" @bind="newInvoice!.InvoiceDate" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Due Date</label>
                    <input type="date" class="form-control" @bind="newInvoice!.DueDate" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Notes</label>
                    <input class="form-control" @bind="newInvoice!.Notes" />
                </div>
