                    @foreach (var item in newInvoiceItems)
                    {
                        <tr>
                            <td><input class="form-control form-control-sm" @bind="item.Description" /></td>
                            <td style="width:80px;"><input type="number" class="form-control form-control-sm" @bind="item.Quantity" @bind:after="RecalcTotals" /></td>
                            <td style="width:120px;"><input type="number" step="0.01" class="form-control form-control-sm" @bind="item.UnitPrice" @bind:after="RecalcTotals" /></td>
                            <td>@((item.Quantity * item.UnitPrice).ToString("C"))</td>
                            <td><button class="btn btn-sm btn-outline-danger" @onclick="() => newInvoiceItems.Remove(item)">×</button></td>
                        </tr>
                    }
                </tbody>
            </table>
            <button class="btn btn-sm btn-outline-secondary mb-2" @onclick="AddLineItem">+ Add Item</button>
            <div class="fw-bold">Total: @runningTotal.ToString("C")</div>
            <div class="mt-2">
                <button class="btn btn-success" @onclick="SaveInvoice">Save Invoice</button>
                <button class="btn btn-secondary" @onclick="() => showForm = false">Cancel</button>
            </div>
        </div>
    </div>
}

<table class="table table-striped">
    <thead>
        <tr><th>#</th><th>Pet</th><th>Date</th><th>Total</th><th>Paid</th><th>Status</th><th>Actions</th></tr>
    </thead>
    <tbody>
        @foreach (var inv in invoices)
        {
            <tr>
                <td>@inv.Id</td>
                <td>@inv.Pet?.Name</td>
                <td>@inv.InvoiceDate.ToShortDateString()</td>
                <td>@inv.TotalAmount.ToString("C")</td>
                <td>@inv.AmountPaid.ToString("C")</td>
                <td><span class="badge @GetStatusBadge(inv.Status)">@inv.Status</span></td>
                <td><button class="btn btn-sm btn-outline-primary" @onclick="() => Nav.NavigateTo($&quot;/billing/{inv.Id}&quot;)">View</button></td>
            </tr>
        }
    </tbody>
</table>

@code {
    private List<Invoice> invoices = new();
    private List<Pet> pets = new();
    private bool showForm;
    private Invoice? newInvoice;
    private List<InvoiceItem> newInvoiceItems = new();
    private decimal runningTotal;

    protected override async Task OnInitializedAsync()
    {
        invoices = await Db.Invoices.Include(i => i.Pet).OrderByDescending(i => i.InvoiceDate).ToListAsync();
        pets = await Db.Pets.OrderBy(p => p.Name).ToListAsync();
    }

    private void ShowCreateForm()
    {
        newInvoice = new Invoice { InvoiceDate = DateTime.Today, DueDate = DateTime.Today.AddDays(30) };
        newInvoiceItems = new List<InvoiceItem> { new InvoiceItem { Quantity = 1 } };
        runningTotal = 0;
        showForm = true;
    }

    private void AddLineItem() => newInvoiceItems.Add(new InvoiceItem { Quantity = 1 });

    private void RecalcTotals()
    {
        runningTotal = newInvoiceItems.Sum(i => i.Quantity * i.UnitPrice);
    }

    private async Task SaveInvoice()
    {
        if (newInvoice == null || newInvoice.PetId == 0) return;
        foreach (var item in newInvoiceItems)
            item.Amount = item.Quantity * item.UnitPrice;
        newInvoice.Items = newInvoiceItems.Where(i => !string.IsNullOrWhiteSpace(i.Description)).ToList();
        newInvoice.TotalAmount = newInvoice.Items.Sum(i => i.Amount);
        Db.Invoices.Add(newInvoice);
        await Db.SaveChangesAsync();
        invoices = await Db.Invoices.Include(i => i.Pet).OrderByDescending(i => i.InvoiceDate).ToListAsync();
        showForm = false;
    }

    private string GetStatusBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Pending => "bg-warning text-dark",
        InvoiceStatus.PartiallyPaid => "bg-info",
        InvoiceStatus.Overdue => "bg-danger",
        _ => "bg-secondary"
    };
}

