+    <table class="table table-bordered" style="table-layout: fixed;">
+        <thead>
+            <tr>
+                <th style="width: 80px;">Time</th>
+                @for (int d = 0; d < 7; d++)
+                {
+                    var date = weekStart.AddDays(d);
+                    <th class="text-center @(date == DateTime.Today ? "table-info" : "")">@date.ToString("ddd M/d")</th>
+                }
+            </tr>
+        </thead>
+        <tbody>
+            @for (int hour = 8; hour <= 17; hour++)
+            {
+                <tr>
+                    <td class="text-nowrap small">@(new TimeOnly(hour, 0).ToString("h:mm tt"))</td>
+                    @for (int d = 0; d < 7; d++)
+                    {
+                        var slotDate = weekStart.AddDays(d);
+                        var slotTime = new DateTime(slotDate.Year, slotDate.Month, slotDate.Day, hour, 0, 0);
+                        var appt = GetAppointmentAt(slotTime);
+                        if (appt != null)
+                        {
+                            <td class="table-primary small p-1" @onclick="() => SelectAppointment(appt)" style="cursor:pointer;">
+                                <strong>@appt.Pet?.Name</strong><br/>
+                                <span>@appt.Reason</span>
+                            </td>
+                        }
+                        else
+                        {
+                            <td class="table-success p-1" @onclick="() => OpenCreateForm(slotTime)" style="cursor:pointer; opacity: 0.5;">
+                                &nbsp;
+                            </td>
+                        }
+                    }
+                </tr>
+            }
+        </tbody>
+    </table>
+</div>
+
+@if (showForm)
+{
+    <div class="card mt-3">
+        <div class="card-body">
+            <h5>@(selectedAppointment?.Id > 0 ? "Edit Appointment" : "New Appointment")</h5>
+            <div class="row g-2">
+                <div class="col-md-3">
+                    <label class="form-label">Pet</label>
+                    <select class="form-select" @bind="selectedAppointment!.PetId">
+                        <option value="0">-- Select Pet --</option>
+                        @foreach (var p in pets)
+                        {
+                            <option value="@p.Id">@p.Name (@p.Species)</option>
+                        }
+                    </select>
+                </div>
+                <div class="col-md-3">
+                    <label class="form-label">Date/Time</label>
+                    <input type="datetime-local" class="form-control" @bind="selectedAppointment!.ScheduledAt" />
+                </div>
+                <div class="col-md-2">
+                    <label class="form-label">Duration (min)</label>
+                    <input type="number" class="form-control" @bind="selectedAppointment!.DurationMinutes" />
+                </div>
+                <div class="col-md-4">
+                    <label class="form-label">Reason</label>
+                    <input class="form-control" @bind="selectedAppointment!.Reason" />
+                </div>
+                <div class="col-md-3">
+                    <label class="form-label">Veterinarian</label>
+                    <input class="form-control" @bind="selectedAppointment!.VeterinarianName" />
+                </div>
+                <div class="col-md-3">
+                    <label class="form-label">Notes</label>
+                    <input class="form-control" @bind="selectedAppointment!.Notes" />
+                </div>
+                <div class="col-md-6 d-flex align-items-end gap-1">
+                    <button class="btn btn-success" @onclick="SaveAppointment">Save</button>
+                    @if (selectedAppointment?.Id > 0)
+                    {
+                        <button class="btn btn-danger" @onclick="CancelAppointment">Cancel Appointment</button>
+                    }
+                    <button class="btn btn-secondary" @onclick="CloseForm">Close</button>
+                </div>
+            </div>
+        </div>
+    </div>
+}
+
+@code {
+    private DateTime weekStart;
+    private List<Appointment> appointments = new();
+    private List<Pet> pets = new();
+    private bool showForm;
+    private Appointment? selectedAppointment;
+
+    protected override async Task OnInitializedAsync()
+    {
+        GoToToday();
+        pets = await Db.Pets.OrderBy(p => p.Name).ToListAsync();
+        await LoadAppointments();
+    }
+
+    private void GoToToday()
+    {
+        var today = DateTime.Today;
+        weekStart = today.AddDays(-(int)today.DayOfWeek);
+    }
+
+    private async Task PreviousWeek()
+    {
+        weekStart = weekStart.AddDays(-7);
+        await LoadAppointments();
+    }
+
+    private async Task NextWeek()
+    {
+        weekStart = weekStart.AddDays(7);
+        await LoadAppointments();
+    }
+
+    private async Task LoadAppointments()
+    {
+        var weekEnd = weekStart.AddDays(7);
+        appointments = await Db.Appointments
+            .Include(a => a.Pet)
+            .Where(a => a.ScheduledAt >= weekStart && a.ScheduledAt < weekEnd && a.Status != AppointmentStatus.Cancelled)
+            .ToListAsync();
+    }
+
+    private Appointment? GetAppointmentAt(DateTime slotTime)
+    {
+        return appointments.FirstOrDefault(a => a.ScheduledAt.Date == slotTime.Date && a.ScheduledAt.Hour == slotTime.Hour);
+    }
+
+    private void OpenCreateForm(DateTime slotTime)
+    {
+        selectedAppointment = new Appointment { ScheduledAt = slotTime };
+        showForm = true;
+    }
+
+    private void SelectAppointment(Appointment appt)
+    {
+        selectedAppointment = appt;
+        showForm = true;
+    }
+
+    private void CloseForm()
+    {
+        showForm = false;
+        selectedAppointment = null;
+    }
+
+    private async Task SaveAppointment()
+    {
+        if (selectedAppointment == null || selectedAppointment.PetId == 0) return;
+        if (selectedAppointment.Id == 0)
+            Db.Appointments.Add(selectedAppointment);
+        await Db.SaveChangesAsync();
+        await LoadAppointments();
+        showForm = false;
+        selectedAppointment = null;
+    }
+
+    private async Task CancelAppointment()
+    {
+        if (selectedAppointment == null) return;
+        selectedAppointment.Status = AppointmentStatus.Cancelled;
+        await Db.SaveChangesAsync();
+        await LoadAppointments();
+        showForm = false;
+        selectedAppointment = null;
+    }
+}
